import { createI18n } from 'vue-i18n'

import uzLatn from '../services/locales/uz-latn.json'
import uzCyril from '../services/locales/uz.json'
import ru from '../services/locales/ru.json'

export default function useI18nOptions(){
    const i18n = createI18n({
        locale:'uz-latn',
        fallbackLocale:['uz-cyril'],
        messages:{
            'uz-latn': uzLatn,
            'uz': uzCyril,
            'ru': ru,
        }
    })
    return {
        i18n
    }
}