import {createRouter, createWebHistory} from 'vue-router'
import routes from "./routes";
import middlewarePipeline from "./middlewarePipeline";
import store from "../store";

const router = createRouter({
    history: createWebHistory(process.env.BASE_URL),
    routes
})

router.beforeEach((to, from, next) => {
    const projectPaths = ['auth', '404', 'index', 'vice-id', 'day','week','create-event','create-event-id',
        'pre-events','event-info','chat','users-info','users-info-id','create-user',
        'users-info-admin','users-info-id-admin','edit-user-admin','direction','pre-event-edit','event-edit','profile','profile-edit', 'week-id', 'day-id'];
    if (!projectPaths.includes(to.name)) {
        next("/404");
    }
    if (!to.meta.middleware) {
        return next();
    }
    const middleware = to.meta.middleware;
    const context = {
        store,
        to,
        from,
        next,
    };

    return middleware[0]({
        ...context,
        nextMiddleware: middlewarePipeline(context, middleware, 1)
    });
});

export default router
