export default {
    state: {},
    getters: {},
    mutations: {},
    actions: {
        async errorHandler({commit, dispatch}, error) {
            console.error('ErrorHandler',error?.response)
            if(error?.response?.data){
                Object.values(error?.response?.data).map((errItem)=>{
                    if(errItem){
                        if(errItem instanceof Array){
                            errItem.map(errorMessage=>{
                                dispatch('toast', {
                                    type: 'error',
                                    message: errorMessage,
                                }, {root: true});
                            })
                        }else {
                            dispatch('toast', {
                                type: 'error',
                                message: errItem,
                            }, {root: true});
                        }
                    }
                })
            }
            else {
                await dispatch('toast', {
                    type: 'error',
                    message: 'Server bilan bogʻliq xatolik yuz berdi',
                }, {root: true});
            }

        },
    },
};
