import http from "../plugins/axios";


export default {
    state: () => ({
        userInfo: {
            id:"",
            fatherName: "",
            firstName: "",
            lastName: "",
            position: "",
            organisationId:"",
            photoPath:"",
            role:  { name: "", label: "" }
        },
        isAuth: false
    }),
    getters: {
        getUserInfo(state) {
            return state.userInfo;
        },
        isAuth(state) {
            return state.isAuth;
        }
    },
    mutations: {
        setUserState(state, payload) {
            state.isAuth = true;
            state.userInfo = {
                ...payload,
            };
        }
    },
    actions: {
        async me({commit}) {
            const resp = (await http.get("api/user/me")).data;
            await commit("setUserState", resp.data);
        }
    }
};
